// Parse Greenhouse API response, filter by title keywords AND geography
const apiResponse = $input.first().json;

const prep = $('Prepare Company Data').item.json;
const companyName = prep.companyName;
const keywordsRaw = prep.titleKeywords || '';
const apiEndpoint = prep.apiEndpoint;

if (!companyName) {
  throw new Error('Company Name missing from Prepare Company Data node.');
}

// Dynamic geography from Profile table
const profileData = $('Get Profile').first().json;
const geoField = profileData.fields 
  ? profileData.fields['Target Geography'] 
  : profileData['Target Geography'];
const userGeographies = Array.isArray(geoField) ? geoField : ['Remote Global'];

const GEO_MAP = {
  'Canada': ['canada', 'toronto', 'vancouver', 'montreal', 'ottawa', 'calgary', 'mississauga', 'remote - canada', 'remote canada'],
  'USA': ['united states', 'usa', 'us only', 'remote - us', 'remote us', 'new york', 'san francisco', 'los angeles', 'seattle', 'chicago', 'austin', 'boston'],
  'Remote Global': ['remote', 'worldwide', 'global', 'anywhere'],
  'Remote North America': ['remote - north america', 'remote north america', 'remote - na', 'remote us', 'remote canada'],
  'Remote Canada': ['remote - canada', 'remote canada'],
  'EMEA': ['emea', 'europe', 'london', 'berlin', 'paris', 'amsterdam', 'dublin'],
  'Remote Europe': ['remote - europe', 'remote europe', 'remote - emea', 'remote emea'],
  'UK': ['united kingdom', 'uk', 'london', 'manchester', 'edinburgh'],
  'Germany': ['germany', 'berlin', 'munich', 'hamburg', 'frankfurt'],
  'Netherlands': ['netherlands', 'amsterdam', 'rotterdam', 'the hague'],
  'France': ['france', 'paris', 'lyon', 'marseille'],
  'Ireland': ['ireland', 'dublin', 'cork'],
  'Australia': ['australia', 'sydney', 'melbourne', 'brisbane'],
  'Singapore': ['singapore'],
  'India': ['india', 'bangalore', 'bengaluru', 'mumbai', 'hyderabad', 'pune', 'delhi', 'gurgaon', 'noida'],
  'APAC': ['apac', 'asia', 'singapore', 'tokyo', 'sydney', 'australia'],
  'Remote APAC': ['remote - apac', 'remote apac', 'remote - asia', 'remote asia'],
  'Remote LATAM': ['remote - latam', 'remote latam', 'remote - latin america']
};

const allowedLocationKeywords = new Set();
for (const geo of userGeographies) {
  const geoKws = GEO_MAP[geo] || [];
  geoKws.forEach(kw => allowedLocationKeywords.add(kw));
}

const matchesGeography = (locationName) => {
  if (!locationName) return false;
  if (allowedLocationKeywords.size === 0) return true;
  const loc = locationName.toLowerCase();
  for (const kw of allowedLocationKeywords) {
    if (loc.includes(kw)) {
      if (kw === 'remote' && (loc.includes('us only') || loc.includes('united states only'))) {
        if (!userGeographies.includes('USA')) continue;
      }
      return true;
    }
  }
  return false;
};

const keywords = keywordsRaw
  .split(',')
  .map(k => k.trim().toLowerCase())
  .filter(k => k.length > 0);

const jobs = (apiResponse && apiResponse.jobs) ? apiResponse.jobs : [];

if (jobs.length === 0) {
  return [{
    json: {
      _empty: true,
      _company: companyName,
      detailUrl: 'https://boards-api.greenhouse.io/v1/boards/airtable/jobs'
    }
  }];
}

const titleFiltered = jobs.filter(job => {
  if (keywords.length === 0) return true;
  const title = (job.title || '').toLowerCase();
  return keywords.some(kw => title.includes(kw));
});

const filtered = titleFiltered.filter(job => {
  const locationName = (job.location && job.location.name) || '';
  return matchesGeography(locationName);
});

if (filtered.length === 0) {
  return [{
    json: {
      _empty: true,
      _company: companyName,
      detailUrl: 'https://boards-api.greenhouse.io/v1/boards/airtable/jobs'
    }
  }];
}

const fnv1aHash = (str) => {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
};

const items = filtered.map(job => {
  const title = job.title || 'Untitled';
  const location = (job.location && job.location.name) || 'Not specified';
  const applyLink = job.absolute_url || '';
  const detailUrl = `${apiEndpoint}/${job.id}`;

  const hashInput = `${title}|${companyName}|${applyLink}`;
  const jobId = fnv1aHash(hashInput) + '-' + companyName.substring(0, 3).toLowerCase();

  return {
    json: {
      jobId: jobId,
      jobTitle: title,
      company: companyName,
      location: location,
      applyLink: applyLink,
      detailUrl: detailUrl,
      source: 'Greenhouse',
      sourceQuery: companyName,
      sourceTag: 'Tracked Company',
      discoveryDate: new Date().toISOString().split('T')[0]
    }
  };
});

return items;

// Aggregate results from all company loops into a single deduplicated list
// This runs after Loop Companies completes all iterations

const allItems = $input.all();

// Filter out summary-only items (those with _empty flag) and keep real job items
const realJobs = allItems.filter(item => !item.json._empty && item.json.jobId);

// In-memory deduplication by jobId (in case same job appeared in multiple companies, unlikely but defensive)
const seen = new Set();
const unique = [];
for (const item of realJobs) {
  if (!seen.has(item.json.jobId)) {
    seen.add(item.json.jobId);
    unique.push(item);
  }
}

return unique;

// Filter aggregated jobs against existing Job IDs in Pipeline (deduplication)

const aggregatedJobs = $('Aggregate All Jobs').all();
const existingRecords = $('Get Existing Job IDs').all();

const existingIds = new Set();
for (const record of existingRecords) {
  let jobId = null;
  if (record.json.fields && record.json.fields['Job ID']) {
    jobId = record.json.fields['Job ID'];
  } else if (record.json['Job ID']) {
    jobId = record.json['Job ID'];
  }
  if (jobId) existingIds.add(jobId);
}

const netNew = aggregatedJobs.filter(item => !existingIds.has(item.json.jobId));

// Safety brake: cap at 100 new records per run
if (netNew.length > 100) {
  throw new Error(`Safety brake: ${netNew.length} net-new jobs exceeds 100 limit. Review your Tracked Companies title keywords — they may be too broad. Increase the cap in this Code node if this is intentional.`);
}

if (netNew.length === 0) {
  return [{ json: { _empty: true, _message: `${aggregatedJobs.length} jobs found, all already in Pipeline` } }];
}

return netNew;

const allInputs = $input.all();
const parsedJobs = $('Parse & Filter Jobs').all();

// Two-step stripper: decode entities first, then strip tags
const stripHtml = (html) => {
  if (!html || typeof html !== 'string') return '';

  let text = html;

  // STEP 1: Decode HTML entities (Greenhouse double-encodes their content)
  // This turns &lt;div&gt; into <div> so we can then strip it
  text = text.split('&lt;').join('<');
  text = text.split('&gt;').join('>');
  text = text.split('&quot;').join('"');
  text = text.split('&#39;').join("'");
  text = text.split('&apos;').join("'");
  text = text.split('&nbsp;').join(' ');
  text = text.split('&amp;').join('&');  // Must be last to avoid re-decoding

  // STEP 2: Now strip the actual HTML tags using character walking
  let result = '';
  let inTag = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (ch === '<') {
      inTag = true;
      // Add space when closing block-level tags for readability
      const lookahead = text.substring(i, i + 5).toLowerCase();
      if (lookahead.startsWith('</p>') || lookahead.startsWith('</div') || 
          lookahead.startsWith('</li>') || lookahead.startsWith('</h1>') ||
          lookahead.startsWith('</h2>') || lookahead.startsWith('</h3>') ||
          lookahead.startsWith('<br') || lookahead.startsWith('</tr>')) {
        result += ' ';
      }
    } else if (ch === '>') {
      inTag = false;
    } else if (!inTag) {
      result += ch;
    }
  }
  text = result;

  // STEP 3: Decode any remaining entities (numeric ones, special chars)
  const extras = [
    ['&hellip;', '...'],
    ['&mdash;', '-'],
    ['&ndash;', '-'],
    ['&rsquo;', "'"],
    ['&lsquo;', "'"],
    ['&rdquo;', '"'],
    ['&ldquo;', '"'],
    ['&#8217;', "'"],
    ['&#8220;', '"'],
    ['&#8221;', '"']
  ];
  for (const [entity, replacement] of extras) {
    text = text.split(entity).join(replacement);
  }

  // STEP 4: Collapse whitespace
  while (text.indexOf('  ') !== -1) {
    text = text.split('  ').join(' ');
  }

  return text.trim();
};

const merged = [];
for (let i = 0; i < allInputs.length; i++) {
  const detailResponse = allInputs[i].json;
  const parsedJob = parsedJobs[i] ? parsedJobs[i].json : null;

  if (!parsedJob || parsedJob._empty) {
    merged.push({
      json: {
        _empty: true,
        _company: parsedJob ? parsedJob._company : 'unknown'
      }
    });
    continue;
  }

  const description = stripHtml(detailResponse.content || '[Description not available]');

  merged.push({
    json: {
      jobId: parsedJob.jobId,
      jobTitle: parsedJob.jobTitle,
      company: parsedJob.company,
      location: parsedJob.location,
      applyLink: parsedJob.applyLink,
      jobDescription: description,
      source: parsedJob.source,
      sourceQuery: parsedJob.sourceQuery,
      sourceTag: parsedJob.sourceTag,
      discoveryDate: parsedJob.discoveryDate
    }
  });
}

if (merged.length === 0) {
  return [{ json: { _empty: true, _company: 'placeholder' } }];
}

return merged;
